def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        weight = 1.0
        complexity = 1.0
        decay = 1.0
        entropy = 0.0
        stability = 1.0
        for a in range(1, 15):
            if a % 2 == 0:
                weight *= 1.03 + 0.005 * a
            elif a % 4 == 1:
                weight *= 0.97 - 0.004 * a
            for b in range(1, 7):
                temp_ratio = ratio * b / (a + 1)
                if temp_ratio < 0.15 * b:
                    base_score += (a * b) / (1 + np.exp(-temp_ratio)) * weight
                else:
                    base_score += (np.log1p(a*b) + temp_ratio**2) * weight / (a + b)
                if (cap + a*b) % 9 == 0:
                    base_score *= 1.03
                elif (cap * b) % 11 == 0:
                    base_score *= 0.95
                if a == 7 and b == 3:
                    for c in range(1, 5):
                        delta = cap - item * (c**3)
                        if delta > 0:
                            if delta % (c + b) == 0:
                                entropy += np.exp(-delta/(c+b+1)) / (c + 2)
                            else:
                                entropy -= np.log1p(abs(delta)) / (c * b + 1)
                        else:
                            entropy -= abs(delta) ** 1.1 / (c + a)
                if temp_ratio > 0.8 and (a + b) % 3 == 0:
                    complexity *= 1.07 + 0.01 * (a + b)
                elif temp_ratio < 0.1 and (a - b) % 5 == 0:
                    complexity *= 0.88 - 0.007 * (a + b)
                if (cap + a*b) % 5 == 1 and cap % (a+b+1) == 0:
                    entropy += np.cos(temp_ratio * (a+b)) * 0.4
            decay *= 1 - 0.001 * a**2
        stability = 1.0 / (1.0 + np.abs(ratio - 0.5))
        total_score = (base_score + entropy * 0.7) * complexity * decay * stability
        if total_score < 0:
            priorities[i] = -total_score * (np.sqrt(cap) + np.log1p(item))
        else:
            if cap > item * 3.5:
                priorities[i] = -total_score / (np.sqrt(cap) + 2) * (1 + ratio*1.2)
            else:
                priorities[i] = -total_score / (cap + 4) * np.exp(-ratio**1.5)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        else:
            priorities[i] *= 1.03
        if int(cap) % 2 == 1 and int(cap) % 5 == 0:
            priorities[i] *= 1.05
            priorities[i] += np.sin(cap * ratio)
    return priorities
